"""
AstroHub E2E 测试 v2 - 基于实际 UI 结构

测试流程:
1. 打开设备管理页面
2. 选择在线设备并连接
3. 切换到主控台页面
4. 验证视频播放器状态
5. 验证 PTZ 控制面板
6. 断开设备

Author: 开发工厂
"""

import asyncio
from playwright.async_api import async_playwright, Page, Browser
from datetime import datetime
import json

# 测试配置
BASE_URL = "http://localhost:8000"
SCREENSHOT_DIR = "C:/Users/admin/.openclaw/agents/dev-factory/astrohub/data/e2e_screenshots"

# 问题列表
issues: list[dict] = []


def log_issue(category: str, description: str, severity: str = "medium", details: str = ""):
    """记录问题"""
    issues.append({
        "category": category,
        "description": description,
        "severity": severity,
        "details": details,
        "timestamp": datetime.now().isoformat(),
    })


async def test_main_page(page: Page):
    """测试1: 主页面加载"""
    print("\n[TEST 1] Main Page Load...")

    try:
        await page.goto(BASE_URL, timeout=15000)
        await page.wait_for_load_state("networkidle", timeout=15000)

        # 检查标题
        title = await page.title()
        print(f"  Title: {title}")

        # 检查 WebSocket 状态
        ws_dot = await page.query_selector("#wsDot")
        if ws_dot:
            cls = await ws_dot.get_attribute("class")
            print(f"  WebSocket: {cls}")
            if "red" in cls:
                log_issue("WebSocket", "WebSocket not connected", "medium", f"Status: {cls}")
        else:
            log_issue("WebSocket", "WebSocket indicator not found", "high", "#wsDot missing")

        # 截图
        await page.screenshot(path=f"{SCREENSHOT_DIR}/v2_01_main.png")
        print("  [PASS] Main page loaded")

    except Exception as e:
        log_issue("MainPage", "Main page load failed", "critical", str(e))


async def test_device_management(page: Page):
    """测试2: 设备管理页面"""
    print("\n[TEST 2] Device Management Page...")

    try:
        # 点击设备管理导航按钮 (第二个 nav-btn)
        device_btn = await page.query_selector("button.nav-btn:nth-child(2)")
        if device_btn:
            await device_btn.click()
            await page.wait_for_timeout(1500)

            # 检查设备表格
            device_table = await page.query_selector("table tbody")
            if device_table:
                rows = await device_table.query_selector_all("tr")
                print(f"  Device rows: {len(rows)}")

                if len(rows) == 0:
                    log_issue("DeviceMgmt", "No devices in table", "medium", "Device table is empty")
            else:
                log_issue("DeviceMgmt", "Device table not found", "high", "table tbody missing")

            # 检查发现按钮
            discover_btn = await page.query_selector("#btnDiscover")
            if not discover_btn:
                log_issue("DeviceMgmt", "Discover button not found", "medium", "#btnDiscover missing")

            await page.screenshot(path=f"{SCREENSHOT_DIR}/v2_02_devices.png")
            print("  [PASS] Device management page loaded")
        else:
            log_issue("DeviceMgmt", "Device nav button not found", "high", "nav-btn:nth-child(2) missing")

    except Exception as e:
        log_issue("DeviceMgmt", "Device management test failed", "critical", str(e))


async def test_device_connect(page: Page):
    """测试3: 设备连接"""
    print("\n[TEST 3] Device Connect...")

    try:
        # 回到设备管理页面
        device_btn = await page.query_selector("button.nav-btn:nth-child(2)")
        if device_btn:
            await device_btn.click()
            await page.wait_for_timeout(1000)

        # 查找连接按钮 (在线设备行中的"连接"按钮)
        connect_btns = await page.query_selector_all("button.btn-primary.btn-sm")
        connect_found = False

        for btn in connect_btns:
            text = await btn.inner_text()
            if "connect" in text.lower() or "连接" in text:
                connect_found = True
                print(f"  Found connect button: {text}")
                await btn.click()
                await page.wait_for_timeout(3000)  # 等待连接

                # 检查 Toast 消息
                toast = await page.query_selector(".toast.show")
                if toast:
                    toast_text = await toast.inner_text()
                    print(f"  Toast: {toast_text[:100]}")
                    if "success" in toast_text.lower() or "成功" in toast_text:
                        print("  [PASS] Device connected successfully")
                    elif "error" in toast_text.lower() or "失败" in toast_text:
                        log_issue("Connect", "Device connect failed", "high", toast_text)
                else:
                    print("  No toast message shown")

                break

        if not connect_found:
            log_issue("Connect", "No connect button found", "medium", "No online device with connect button")

        await page.screenshot(path=f"{SCREENSHOT_DIR}/v2_03_connect.png")

    except Exception as e:
        log_issue("Connect", "Device connect test failed", "critical", str(e))


async def test_console_page(page: Page):
    """测试4: 主控台页面"""
    print("\n[TEST 4] Console Page...")

    try:
        # 点击主控台导航按钮 (第三个 nav-btn)
        console_btn = await page.query_selector("button.nav-btn:nth-child(3)")
        if console_btn:
            await console_btn.click()
            await page.wait_for_timeout(1500)

            # 检查 PTZ 控制面板
            ptz_controls = await page.query_selector(".ptz-controls")
            if ptz_controls:
                ptz_btns = await ptz_controls.query_selector_all("button")
                print(f"  PTZ buttons: {len(ptz_btns)}")
            else:
                log_issue("Console", "PTZ controls not found", "high", ".ptz-controls missing")

            # 检查 WASM 视频播放器
            video_player = await page.query_selector("#divPlugin_playCanvas0")
            if video_player:
                print("  [PASS] WASM video player found")
            else:
                log_issue("Console", "WASM video player not found", "high", "#divPlugin_playCanvas0 missing")

            # 检查设备状态显示
            device_status = await page.query_selector(".advanced-status-panel")
            if device_status:
                status_text = await device_status.inner_text()
                print(f"  Status panel: {status_text[:100]}...")

            await page.screenshot(path=f"{SCREENSHOT_DIR}/v2_04_console.png")
            print("  [PASS] Console page loaded")
        else:
            log_issue("Console", "Console nav button not found", "high", "nav-btn:nth-child(3) missing")

    except Exception as e:
        log_issue("Console", "Console page test failed", "critical", str(e))


async def test_advanced_page(page: Page):
    """测试5: 高级功能页面"""
    print("\n[TEST 5] Advanced Page...")

    try:
        # 点击高级功能导航按钮 (第五个 nav-btn)
        adv_btn = await page.query_selector("button.nav-btn:nth-child(5)")
        if adv_btn:
            await adv_btn.click()
            await page.wait_for_timeout(1500)

            # 检查设备选择下拉框
            device_select = await page.query_selector("#advConnectDevice")
            if device_select:
                options = await device_select.query_selector_all("option")
                print(f"  Device selector options: {len(options)}")

                if len(options) == 0:
                    log_issue("Advanced", "No device options in selector", "medium", "#advConnectDevice empty")
            else:
                log_issue("Advanced", "Device selector not found", "high", "#advConnectDevice missing")

            # 检查侧边栏菜单
            sidebar_items = await page.query_selector_all(".adv-menu-item")
            print(f"  Sidebar items: {len(sidebar_items)}")

            # 检查功能测试按钮
            func_btn = await page.query_selector("#btnAdvRun")
            if not func_btn:
                log_issue("Advanced", "Run button not found", "medium", "#btnAdvRun missing")

            await page.screenshot(path=f"{SCREENSHOT_DIR}/v2_05_advanced.png")
            print("  [PASS] Advanced page loaded")
        else:
            log_issue("Advanced", "Advanced nav button not found", "high", "nav-btn:nth-child(5) missing")

    except Exception as e:
        log_issue("Advanced", "Advanced page test failed", "critical", str(e))


async def test_api_health(page: Page):
    """测试6: API 健康检查"""
    print("\n[TEST 6] API Health Check...")

    try:
        # 健康检查 API
        health = await page.evaluate("""
            async () => {
                try {
                    const resp = await fetch('/api/v1/health');
                    return { status: resp.status, ok: resp.ok };
                } catch (e) {
                    return { error: e.message };
                }
            }
        """)

        if health.get("ok"):
            print(f"  [PASS] Health API OK (status: {health['status']})")
        else:
            log_issue("API", "Health API failed", "high", str(health))

        # 设备列表 API
        devices = await page.evaluate("""
            async () => {
                try {
                    const resp = await fetch('/api/v1/ptz/devices');
                    const data = await resp.json();
                    return { status: resp.status, count: Array.isArray(data) ? data.length : 0, ok: resp.ok };
                } catch (e) {
                    return { error: e.message };
                }
            }
        """)

        if devices.get("ok"):
            print(f"  [PASS] Devices API OK (count: {devices.get('count', 0)})")
        else:
            log_issue("API", "Devices API failed", "high", str(devices))

        # PTZ 状态 API
        ptz_status = await page.evaluate("""
            async () => {
                try {
                    const resp = await fetch('/api/v1/ptz/status');
                    return { status: resp.status, ok: resp.ok };
                } catch (e) {
                    return { error: e.message };
                }
            }
        """)

        if ptz_status.get("ok"):
            print(f"  [PASS] PTZ status API OK")
        else:
            log_issue("API", "PTZ status API failed", "medium", str(ptz_status))

    except Exception as e:
        log_issue("API", "API health check failed", "critical", str(e))


async def run_tests():
    """运行所有测试"""
    print("=" * 60)
    print("AstroHub E2E Test Report v2")
    print("=" * 60)
    print(f"Test Time: {datetime.now().isoformat()}")
    print(f"Target: {BASE_URL}")
    print("=" * 60)

    async with async_playwright() as p:
        browser = await p.chromium.launch(headless=True)
        context = await browser.new_context(
            viewport={"width": 1920, "height": 1080},
            locale="zh-CN",
        )
        page = await context.new_page()

        try:
            await test_main_page(page)
            await test_device_management(page)
            await test_device_connect(page)
            await test_console_page(page)
            await test_advanced_page(page)
            await test_api_health(page)

        except Exception as e:
            log_issue("TestFramework", "Test execution error", "critical", str(e))

        finally:
            await browser.close()

    # 输出报告
    print("\n" + "=" * 60)
    print("ISSUE REPORT")
    print("=" * 60)

    if issues:
        severity_order = {"critical": 0, "high": 1, "medium": 2, "low": 3}
        sorted_issues = sorted(issues, key=lambda x: severity_order.get(x["severity"], 4))

        print(f"\nFound {len(issues)} issues:\n")

        for i, issue in enumerate(sorted_issues, 1):
            print(f"{i}. [{issue['severity'].upper()}] {issue['category']}")
            print(f"   {issue['description']}")
            if issue['details']:
                print(f"   Details: {issue['details']}")
            print()

        # 统计
        print("-" * 40)
        print(f"Summary: Critical={sum(1 for i in issues if i['severity']=='critical')}, "
              f"High={sum(1 for i in issues if i['severity']=='high')}, "
              f"Medium={sum(1 for i in issues if i['severity']=='medium')}, "
              f"Low={sum(1 for i in issues if i['severity']=='low')}")
    else:
        print("\nNo issues found. All tests passed!")

    # 保存报告
    report_path = "C:/Users/admin/.openclaw/agents/dev-factory/astrohub/data/e2e_report_v2.json"
    with open(report_path, "w", encoding="utf-8") as f:
        json.dump({
            "test_time": datetime.now().isoformat(),
            "target": BASE_URL,
            "issues": issues,
            "total_issues": len(issues),
        }, f, indent=2, ensure_ascii=False)

    print(f"\nReport saved: {report_path}")


if __name__ == "__main__":
    asyncio.run(run_tests())

