"""
AstroHub E2E - 视频画面测试
1. 连接设备
2. 等待WASM SDK登录+视频流
3. 截图验证画面
"""
import asyncio
from playwright.async_api import async_playwright
from datetime import datetime
import json

BASE_URL = "http://localhost:8000"
SCREENSHOT_DIR = "C:/Users/admin/.openclaw/agents/dev-factory/astrohub/data/e2e_screenshots"

issues = []

def log_issue(cat, desc, sev="medium", det=""):
    issues.append({"category": cat, "description": desc, "severity": sev, "details": det, "time": datetime.now().isoformat()})

async def run():
    print("=" * 60)
    print("AstroHub Video Test")
    print("=" * 60)

    async with async_playwright() as p:
        browser = await p.chromium.launch(headless=True)
        page = await browser.new_page(viewport={"width": 1920, "height": 1080})

        # 1. Load page
        print("\n[1] Loading page...")
        await page.goto(BASE_URL, timeout=15000)
        await page.wait_for_load_state("networkidle", timeout=15000)
        await page.screenshot(path=f"{SCREENSHOT_DIR}/vt_01_loaded.png")

        # 2. Go to device management page
        print("[2] Opening device management...")
        device_btn = await page.query_selector("button.nav-btn:nth-child(2)")
        if device_btn:
            await device_btn.click()
            await page.wait_for_timeout(1500)
        await page.screenshot(path=f"{SCREENSHOT_DIR}/vt_02_devices.png")

        # 3. Check device list
        print("[3] Checking device list...")
        device_data = await page.evaluate("""
            async () => {
                try {
                    const resp = await fetch('/api/v1/devices');
                    const data = await resp.json();
                    return data;
                } catch(e) { return {error: e.message}; }
            }
        """)
        print(f"  Devices API: {json.dumps(device_data, ensure_ascii=False)[:200]}")

        devices = device_data.get("data", [])
        if not devices:
            log_issue("Device", "No devices found", "high", "Cannot test video without device")
            print("  No devices! Aborting video test.")
            await browser.close()
            return

        # Find online device or first device
        target = None
        for d in devices:
            if d.get("online"):
                target = d
                break
        if not target:
            target = devices[0]

        print(f"  Target device: {target.get('ip')} (online={target.get('online')})")

        # 4. Connect device via API
        print("[4] Connecting device via API...")
        target_ip = target.get("ip", "")

        connect_result = await page.evaluate(f"""
            async () => {{
                try {{
                    // Get credentials first
                    const credResp = await fetch('/api/v1/ptz/devices/{target_ip}/credentials');
                    const creds = await credResp.json();
                    const username = (creds && creds.success) ? creds.username : 'admin';
                    const password = (creds && creds.success) ? creds.password : '';

                    // Connect
                    const resp = await fetch('/api/v1/devices/{target_ip}/connect', {{
                        method: 'POST',
                        headers: {{'Content-Type': 'application/json'}},
                        body: JSON.stringify({{username: username, password: password, port: 80}})
                    }});
                    return await resp.json();
                }} catch(e) {{ return {{error: e.message}}; }}
            }}
        """)
        print(f"  Connect result: {json.dumps(connect_result, ensure_ascii=False)[:200]}")
        await page.wait_for_timeout(2000)
        await page.screenshot(path=f"{SCREENSHOT_DIR}/vt_03_connected.png")

        # 5. Set window.connectedDevice and trigger WASM login
        print("[5] Setting connectedDevice and triggering WASM login...")

        # Get device info for connectedDevice
        device_info = await page.evaluate(f"""
            () => {{
                const dev = (window.allDevices || []).find(d => d.ip === '{target_ip}');
                return dev || {{ip: '{target_ip}'}};
            }}
        """)
        print(f"  Device info: {json.dumps(device_info, ensure_ascii=False)[:200]}")

        # Set connectedDevice and call clickLogin2
        login_result = await page.evaluate(f"""
            () => {{
                const dev = (window.allDevices || []).find(d => d.ip === '{target_ip}');
                if (dev) {{
                    window.connectedDevice = {{
                        ip: dev.ip,
                        model: dev.model || '',
                        name: dev.name || dev.device_name || '',
                        mac: dev.mac || '',
                        username: 'admin',
                        password: '',
                        port: 80,
                        online: true
                    }};
                }} else {{
                    window.connectedDevice = {{
                        ip: '{target_ip}',
                        model: '',
                        name: '',
                        mac: '',
                        username: 'admin',
                        password: '',
                        port: 80,
                        online: true
                    }};
                }}

                // Trigger WASM login
                if (typeof window.clickLogin2 === 'function') {{
                    try {{
                        window.clickLogin2();
                        return {{success: true, message: 'clickLogin2 called'}};
                    }} catch(e) {{
                        return {{success: false, message: 'clickLogin2 error: ' + e.message}};
                    }}
                }} else {{
                    return {{success: false, message: 'clickLogin2 not found'}};
                }}
            }}
        """)
        print(f"  WASM login: {json.dumps(login_result, ensure_ascii=False)[:200]}")

        # 6. Wait for video stream
        print("[6] Waiting for video stream (10s)...")
        await page.wait_for_timeout(10000)
        await page.screenshot(path=f"{SCREENSHOT_DIR}/vt_04_video_wait10.png")

        # 7. Check video canvas content
        print("[7] Checking video canvas...")
        canvas_info = await page.evaluate("""
            () => {
                const canvas = document.getElementById('divPlugin_playCanvas0');
                if (!canvas) return {found: false};

                const ctx = canvas.getContext('2d');
                const w = canvas.width;
                const h = canvas.height;

                if (w === 0 || h === 0) return {found: true, width: w, height: h, hasContent: false, reason: 'zero size'};

                // Sample pixels from center
                try {
                    const imageData = ctx.getImageData(Math.floor(w/2) - 5, Math.floor(h/2) - 5, 10, 10);
                    const data = imageData.data;
                    let nonBlack = 0;
                    let total = data.length / 4;
                    for (let i = 0; i < data.length; i += 4) {
                        if (data[i] > 5 || data[i+1] > 5 || data[i+2] > 5) nonBlack++;
                    }
                    return {
                        found: true,
                        width: w,
                        height: h,
                        hasContent: nonBlack > 0,
                        nonBlackPixels: nonBlack,
                        totalPixels: total,
                        ratio: (nonBlack / total * 100).toFixed(1) + '%'
                    };
                } catch(e) {
                    return {found: true, width: w, height: h, hasContent: false, reason: e.message};
                }
            }
        """)
        print(f"  Canvas: {json.dumps(canvas_info)}")

        if canvas_info.get("found") and canvas_info.get("hasContent"):
            print("  >>> VIDEO CONTENT DETECTED! <<<")
        elif canvas_info.get("found") and not canvas_info.get("hasContent"):
            log_issue("Video", "Canvas exists but no video content", "high", 
                      f"Size: {canvas_info.get('width')}x{canvas_info.get('height')}, Reason: {canvas_info.get('reason', 'all black')}")
        else:
            log_issue("Video", "Canvas not found", "high", "divPlugin_playCanvas0 missing")

        # 8. Wait more and check again
        print("[8] Waiting 10s more...")
        await page.wait_for_timeout(10000)
        await page.screenshot(path=f"{SCREENSHOT_DIR}/vt_05_video_wait20.png")

        canvas_info2 = await page.evaluate("""
            () => {
                const canvas = document.getElementById('divPlugin_playCanvas0');
                if (!canvas) return {found: false};
                const ctx = canvas.getContext('2d');
                const w = canvas.width;
                const h = canvas.height;
                if (w === 0 || h === 0) return {found: true, width: w, height: h, hasContent: false};
                try {
                    const imageData = ctx.getImageData(Math.floor(w/2) - 5, Math.floor(h/2) - 5, 10, 10);
                    const data = imageData.data;
                    let nonBlack = 0;
                    let total = data.length / 4;
                    for (let i = 0; i < data.length; i += 4) {
                        if (data[i] > 5 || data[i+1] > 5 || data[i+2] > 5) nonBlack++;
                    }
                    return {found: true, width: w, height: h, hasContent: nonBlack > 0, nonBlackPixels: nonBlack, totalPixels: total, ratio: (nonBlack/total*100).toFixed(1)+'%'};
                } catch(e) { return {found: true, width: w, height: h, hasContent: false, reason: e.message}; }
            }
        """)
        print(f"  Canvas (20s): {json.dumps(canvas_info2)}")

        # 9. Check WASM SDK status
        print("[9] Checking WASM SDK status...")
        sdk_status = await page.evaluate("""
            () => {
                // Check various WASM SDK variables
                const info = {};
                if (typeof WebVideoCtrl !== 'undefined') info.WebVideoCtrl = 'exists';
                if (window.oWebPlugin) info.oWebPlugin = 'exists';
                if (window.g_iWndIndex !== undefined) info.g_iWndIndex = window.g_iWndIndex;
                if (window.szDeviceIP) info.szDeviceIP = window.szDeviceIP;

                // Check login status
                if (typeof WebVideoCtrl !== 'undefined' && WebVideoCtrl.I_GetDeviceStatus) {
                    try { info.deviceStatus = WebVideoCtrl.I_GetDeviceStatus(); } catch(e) { info.deviceStatus = 'error: ' + e.message; }
                }

                // Check error logs
                if (window._wasmErrors) info.errors = window._wasmErrors;

                return info;
            }
        """)
        print(f"  SDK status: {json.dumps(sdk_status, ensure_ascii=False)[:300]}")

        # 10. Check console errors
        print("[10] Checking browser console errors...")
        console_errors = []
        page.on("console", lambda msg: console_errors.append(f"[{msg.type}] {msg.text}") if msg.type in ["error", "warning"] else None)
        await page.wait_for_timeout(3000)

        if console_errors:
            print(f"  Console messages ({len(console_errors)}):")
            for e in console_errors[:10]:
                print(f"    {e[:120]}")
        else:
            print("  No console errors captured in this window")

        # Final screenshot
        await page.screenshot(path=f"{SCREENSHOT_DIR}/vt_06_final.png")

        await browser.close()

    # Report
    print("\n" + "=" * 60)
    print("VIDEO TEST REPORT")
    print("=" * 60)
    if issues:
        for i, iss in enumerate(issues, 1):
            print(f"{i}. [{iss['severity'].upper()}] {iss['category']}: {iss['description']}")
            if iss['details']: print(f"   {iss['details']}")
    else:
        print("No issues found!")

    # Save
    with open(f"{SCREENSHOT_DIR}/../video_test_report.json", "w", encoding="utf-8") as f:
        json.dump({"issues": issues, "canvas_10s": canvas_info, "canvas_20s": canvas_info2, "sdk": sdk_status}, f, indent=2, ensure_ascii=False)

asyncio.run(run())

edits.newText:
# 4. If no devices, trigger SADP discovery
if not devices:
    print("[4] No devices, triggering SADP discovery...")
    discover_result = await page.evaluate("""
        async () => {
            try {
                const resp = await fetch('/api/v1/discovery/sadp');
                return await resp.json();
            } catch(e) { return {error: e.message}; }
        }
    """)
    print(f"  Discovery: {json.dumps(discover_result, ensure_ascii=False)[:300]}")

