"""
AstroHub Video Test - 使用正确凭证
"""
import asyncio
from playwright.async_api import async_playwright
from datetime import datetime
import json

BASE_URL = "http://localhost:8000"
DEVICE_IP = "192.168.5.72"
USERNAME = "admin"
PASSWORD = "Nftw1357"
PORT = 80
SCREENSHOT_DIR = "C:/Users/admin/.openclaw/agents/dev-factory/astrohub/data/e2e_screenshots"

async def run():
    print("=" * 60)
    print("AstroHub Video Test (with credentials)")
    print("=" * 60)

    async with async_playwright() as p:
        browser = await p.chromium.launch(headless=True)
        page = await browser.new_page(viewport={"width": 1920, "height": 1080})

        # Track console messages
        console_msgs = []
        page.on("console", lambda msg: console_msgs.append(f"[{msg.type}] {msg.text}"))

        # 1. Load page
        print("\n[1] Loading page...")
        await page.goto(BASE_URL, timeout=15000)
        await page.wait_for_load_state("networkidle", timeout=15000)
        await page.screenshot(path=f"{SCREENSHOT_DIR}/vf_01_loaded.png")

        # 2. Connect device via API
        print("[2] Connecting device via API with credentials...")
        connect_result = await page.evaluate(f"""
            async () => {{
                try {{
                    const resp = await fetch('/api/v1/devices/{DEVICE_IP}/connect', {{
                        method: 'POST',
                        headers: {{'Content-Type': 'application/json'}},
                        body: JSON.stringify({{username: '{USERNAME}', password: '{PASSWORD}', port: {PORT}}})
                    }});
                    return await resp.json();
                }} catch(e) {{ return {{error: e.message}}; }}
            }}
        """)
        print(f"  Connect: {json.dumps(connect_result, ensure_ascii=False)[:200]}")
        await page.wait_for_timeout(2000)

        # 3. Set connectedDevice and trigger WASM login
        print("[3] Setting connectedDevice and triggering WASM login...")
        login_result = await page.evaluate(f"""
            () => {{
                window.connectedDevice = {{
                    ip: '{DEVICE_IP}',
                    model: 'iDS-2DF8C832IXS-A',
                    name: 'PTZ',
                    mac: '24-0f-9b-76-41-93',
                    username: '{USERNAME}',
                    password: '{PASSWORD}',
                    port: {PORT},
                    online: true
                }};

                if (typeof window.clickLogin2 === 'function') {{
                    try {{
                        window.clickLogin2();
                        return {{success: true, message: 'clickLogin2 called'}};
                    }} catch(e) {{
                        return {{success: false, message: 'clickLogin2 error: ' + e.message}};
                    }}
                }} else {{
                    return {{success: false, message: 'clickLogin2 not found'}};
                }}
            }}
        """)
        print(f"  WASM login: {json.dumps(login_result, ensure_ascii=False)}")
        await page.screenshot(path=f"{SCREENSHOT_DIR}/vf_02_login.png")

        # 4. Wait for video stream
        print("[4] Waiting for video stream (15s)...")
        await page.wait_for_timeout(15000)
        await page.screenshot(path=f"{SCREENSHOT_DIR}/vf_03_video_15s.png")

        # 5. Check video canvas
        print("[5] Checking video canvas...")
        for attempt in range(3):
            canvas_info = await page.evaluate("""
                () => {
                    const canvas = document.getElementById('divPlugin_playCanvas0');
                    if (!canvas) return {found: false};

                    const ctx = canvas.getContext('2d');
                    const w = canvas.width;
                    const h = canvas.height;

                    if (w === 0 || h === 0) return {found: true, width: w, height: h, hasContent: false, reason: 'zero size'};

                    try {
                        const imageData = ctx.getImageData(0, 0, w, h);
                        const data = imageData.data;
                        let nonBlack = 0;
                        let total = data.length / 4;
                        for (let i = 0; i < data.length; i += 4) {
                            if (data[i] > 10 || data[i+1] > 10 || data[i+2] > 10) nonBlack++;
                        }
                        return {
                            found: true,
                            width: w,
                            height: h,
                            hasContent: nonBlack > total * 0.01,
                            nonBlackPixels: nonBlack,
                            totalPixels: total,
                            ratio: (nonBlack / total * 100).toFixed(2) + '%'
                        };
                    } catch(e) {
                        return {found: true, width: w, height: h, hasContent: false, reason: e.message};
                    }
                }
            """)

            print(f"  Canvas attempt {attempt+1}: {json.dumps(canvas_info)}")

            if canvas_info.get("hasContent"):
                print("  >>> VIDEO CONTENT DETECTED! <<<")
                break

            if attempt < 2:
                print("  No content yet, waiting 5s more...")
                await page.wait_for_timeout(5000)

        await page.screenshot(path=f"{SCREENSHOT_DIR}/vf_04_video_final.png")

        # 6. Check WASM SDK status
        print("\n[6] WASM SDK status...")
        sdk_status = await page.evaluate("""
            () => {
                const info = {};
                if (typeof WebVideoCtrl !== 'undefined') {
                    info.WebVideoCtrl = 'exists';
                    if (WebVideoCtrl.I_GetWindowStatus) {
                        try {
                            info.windowStatus = WebVideoCtrl.I_GetWindowStatus(0);
                        } catch(e) {}
                    }
                }
                if (window.oWebPlugin) info.oWebPlugin = 'exists';
                if (window.g_iWndIndex !== undefined) info.g_iWndIndex = window.g_iWndIndex;
                if (window.szDeviceIP) info.szDeviceIP = window.szDeviceIP;
                return info;
            }
        """)
        print(f"  SDK: {json.dumps(sdk_status, ensure_ascii=False)[:300]}")

        # 7. Console errors
        print("\n[7] Console messages...")
        errors = [m for m in console_msgs if "[error]" in m]
        warnings = [m for m in console_msgs if "[warning]" in m]
        print(f"  Errors: {len(errors)}, Warnings: {len(warnings)}")
        for e in errors[:5]:
            print(f"    {e[:150]}")

        # 8. Check video container visibility
        print("\n[8] Video container check...")
        container_info = await page.evaluate("""
            () => {
                const container = document.getElementById('divPlugin');
                if (!container) return {found: false};
                const rect = container.getBoundingClientRect();
                return {
                    found: true,
                    visible: rect.width > 0 && rect.height > 0,
                    width: rect.width,
                    height: rect.height
                };
            }
        """)
        print(f"  Container: {json.dumps(container_info)}")

        await browser.close()

    # Final report
    print("\n" + "=" * 60)
    print("RESULT")
    print("=" * 60)
    if canvas_info.get("hasContent"):
        print("SUCCESS: Video content detected!")
    else:
        print("FAILED: No video content detected")
        print(f"  Canvas: {canvas_info.get('width')}x{canvas_info.get('height')}, {canvas_info.get('ratio')} non-black")

    # Save report
    with open(f"{SCREENSHOT_DIR}/../video_test_final.json", "w", encoding="utf-8") as f:
        json.dump({
            "canvas": canvas_info,
            "sdk": sdk_status,
            "container": container_info,
            "console_errors": errors[:10],
            "success": canvas_info.get("hasContent", False)
        }, f, indent=2, ensure_ascii=False)
    print(f"\nReport saved.")

asyncio.run(run())

